('4', '1', '2026-04-28 06:13:54', '2026-04-28 06:13:54', '<!-- wp:xfact/hero {\"heroVariant\":\"media\",\"title\":\"*Your partner* behind the systems communities rely on\",\"subtitle\":\"xFact partners with public institutions to design, integrate, secure, and sustain mission-critical technology systems.\",\"align\":\"full\",\"slides\":[{\"src\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-solutions.jpg\",\"alt\":\"Healthcare workers collaborating\",\"position\":\"65% 30%\"},{\"src\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-contact.jpg\",\"alt\":\"Students using technology\",\"position\":\"center 35%\"},{\"src\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-careers.jpg\",\"alt\":\"Volunteers working together\",\"position\":\"center 30%\"},{\"src\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-support.jpg\",\"alt\":\"Public safety operations\",\"position\":\"70% 30%\"}],\"posterImage\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/xfact-hero-poster.png\",\"videoUrl\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/xfact-hero.mp4\",\"buttons\":[{\"label\":\"Let\'s Talk\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->\n\n<!-- wp:xfact/text-section {\"sectionLabel\":\"Our Promise\",\"heading\":\"One Partner. Complete Accountability.\",\"body\":\"Public institutions depend on technology that cannot fail — systems that must remain continuously secure, stable, and available, often across fragmented environments built on legacy infrastructure and multiple vendors. xFact exists to bring those environments together: We integrate, secure, and sustain mission-critical systems under one accountable partnership — so the institutions that serve communities can focus on their mission, not their infrastructure.\"} /-->\n\n<!-- wp:xfact/solutions-grid {\"sectors\":[{\"title\":\"Public safety \\u0026 justice\",\"headline\":\"Law enforcement, courts, corrections, 911 systems\",\"description\":\"Mission-critical systems that require continuous availability and uncompromising security.\",\"iconName\":\"Shield\",\"href\":\"/solutions/public-safety\"},{\"title\":\"Government \\u0026 municipal\",\"headline\":\"State, county, and local agencies\",\"description\":\"Integrated systems that support public works, digital services, and civic infrastructure.\",\"iconName\":\"Landmark\",\"href\":\"/solutions/government\"},{\"title\":\"Education\",\"headline\":\"K-12 districts and higher education\",\"description\":\"Secure infrastructure that protects student data and supports continuous learning.\",\"iconName\":\"GraduationCap\",\"href\":\"/solutions/education\"},{\"title\":\"Health \\u0026 human services\",\"headline\":\"Healthcare, behavioral health, social services\",\"description\":\"Compliant environments that balance accessibility with strict privacy requirements.\",\"iconName\":\"HeartPulse\",\"href\":\"/solutions/health-and-human-services\"},{\"title\":\"Infrastructure \\u0026 managed services\",\"headline\":\"DataServ, an xFact solution\",\"description\":\"Hosted platforms and managed network operations that ensure operational stability.\",\"iconName\":\"ServerCog\",\"badge\":\"DataServ\",\"href\":\"/solutions/infrastructure\"}],\"buttons\":[{\"label\":\"Explore our solutions →\",\"url\":\"/solutions\",\"variant\":\"secondary\"}]} /-->\n\n<!-- wp:xfact/capabilities-pipeline /-->\n\n<!-- wp:xfact/metrics-strip /-->\n\n<!-- wp:xfact/text-section {\"sectionLabel\":\"DataServ Integration\",\"heading\":\"Trusted Services, Expanded Capabilities\",\"badgeText\":\"● Formerly DataServ\",\"body\":\"DataServ has delivered managed IT, cloud, and cybersecurity services to K-12 schools, municipalities, and businesses for years. That experience — and the team behind it — is now part of xFact, giving clients access to a wider range of capabilities without changing the relationships they rely on.\",\"tags\":[{\"label\":\"Managed IT\",\"iconName\":\"Monitor\"},{\"label\":\"Cloud services\",\"iconName\":\"Cloud\"},{\"label\":\"Cybersecurity\",\"iconName\":\"ShieldCheck\"},{\"label\":\"K-12 schools\",\"iconName\":\"School\"},{\"label\":\"Municipalities\",\"iconName\":\"Building2\"},{\"label\":\"Government contracts\",\"iconName\":\"Users\"}]} /-->\n\n<!-- wp:xfact/logo-strip /-->\n\n<!-- wp:xfact/cta-section {\"subtitle\":\"Whether you\'re planning an upgrade, responding to a requirement, or evaluating a long-term partner — we\'re the right conversation to start.\",\"buttons\":[{\"label\":\"Contact xFact\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Home', '', 'publish', 'closed', 'closed', '', 'home', '', '', '2026-05-17 03:43:35', '2026-05-17 03:43:35', '', '0', 'https://xfact2stg.wpenginepowered.com/home/', '0', 'page', '', '0'),
('5', '0', '2026-04-28 06:13:54', '2026-04-28 06:13:54', '<!-- wp:xfact/hero {\"sectionLabel\":\"Solutions\",\"title\":\"Reliable Systems. Stronger Communities.\",\"subtitle\":\"xFact supports mission-critical systems across complex public-sector environments. A single accountable partner improves reliability and reduces complexity.\",\"backgroundImage\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-solutions.jpg\",\"imageAlt\":\"Healthcare workers collaborating\",\"align\":\"full\"} /-->\n\n<!-- wp:xfact/solutions-grid {\"sectionLabel\":\"Industries we support\",\"heading\":\"Purpose-Built for Public-Sector Environments\",\"subtitle\":\"Each industry has its own systems, governance, and accountability demands. Tap into the area that matters to your work.\",\"sectors\":[{\"title\":\"Public Safety \\u0026 Justice\",\"headline\":\"Strengthening Systems That Cannot Fail\",\"description\":\"Public safety agencies operate in environments where technology reliability is critical to real-time operations. Communications infrastructure and secure information environments must remain continuously available while meeting stringent security and compliance requirements.\",\"iconName\":\"Shield\",\"href\":\"/solutions/public-safety\"},{\"title\":\"Municipal, State \\u0026 Local Government\",\"headline\":\"Coordinating Systems That Support Communities\",\"description\":\"State, municipal, and county governments rely on interconnected systems that support essential community services. From public works and administrative operations to digital services and civic infrastructure, these systems must remain secure, resilient, and continuously operational.\",\"iconName\":\"Landmark\",\"href\":\"/solutions/government\"},{\"title\":\"Education\",\"headline\":\"Supporting Learning Through Reliable Systems\",\"description\":\"Educational institutions manage interconnected systems that range from student information and learning management to operational infrastructure.\",\"iconName\":\"GraduationCap\",\"href\":\"/solutions/education\"},{\"title\":\"Health \\u0026 Human Services\",\"headline\":\"Supporting Systems That Serve Communities\",\"description\":\"Health and human services agencies manage systems that must simultaneously ensure accessibility for constituents and comply with stringent privacy requirements.\",\"iconName\":\"HeartPulse\",\"href\":\"/solutions/health-and-human-services\"},{\"title\":\"Infrastructure \\u0026 Managed Services\",\"headline\":\"Resilient Infrastructure for Mission-Critical Systems\",\"description\":\"We provide secure infrastructure environments designed to support the continuous operation of mission-critical public systems, delivering the stability, performance, and security required in high-accountability environments.\",\"iconName\":\"ServerCog\",\"badge\":\"DataServ\",\"href\":\"/solutions/infrastructure\"}],\"buttons\":[]} /-->\n\n<!-- wp:xfact/cta-section {\"align\":\"full\",\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Solutions', '', 'publish', 'closed', 'closed', '', 'solutions', '', '', '2026-05-17 03:43:37', '2026-05-17 03:43:37', '', '0', 'https://xfact2stg.wpenginepowered.com/solutions/', '0', 'page', '', '0'),
('6', '0', '2026-04-28 06:13:55', '2026-04-28 06:13:55', '<!-- wp:xfact/hero {\"sectionLabel\":\"Support\",\"title\":\"Access assistance for your systems and services.\",\"subtitle\":\"Ongoing support maintains system reliability. Our structured processes enable efficient response and timely issue resolution.\",\"backgroundImage\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-support.jpg\",\"imageAlt\":\"Police officer on duty\",\"align\":\"full\"} /-->\n\n<!-- wp:xfact/support-channels /-->\n\n<!-- wp:xfact/cta-section {\"variant\":\"dark\",\"title\":\"Existing Client?\",\"subtitle\":\"Access your support portal to submit tickets, track issues, and review service history.\",\"buttons\":[{\"label\":\"Open Support Portal\",\"url\":\"https://portal.dataservtech.com/\",\"variant\":\"primary\"}]} /-->', 'Support', '', 'publish', 'closed', 'closed', '', 'support', '', '', '2026-05-17 03:43:41', '2026-05-17 03:43:41', '', '0', 'https://xfact2stg.wpenginepowered.com/support/', '0', 'page', '', '0'),
('7', '0', '2026-04-28 06:13:56', '2026-04-28 06:13:56', '<!-- wp:xfact/hero {\"sectionLabel\":\"Careers\",\"title\":\"Work behind the systems communities rely on.\",\"subtitle\":\"Join a team that supports mission-critical technology for public-sector organizations. Build systems that must work every day.\",\"backgroundImage\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-careers.jpg\",\"imageAlt\":\"Volunteers working together\",\"align\":\"full\"} /-->\n\n<!-- wp:xfact/feature-cards {\"sectionLabel\":\"Why xFact\",\"heading\":\"What it means to work here\",\"cards\":[{\"title\":\"Mission-Driven Work\",\"description\":\"Every project supports systems critical to public services — from public safety to education to healthcare.\",\"iconName\":\"Target\"},{\"title\":\"High-Accountability Environments\",\"description\":\"Our teams operate in environments where reliability matters. The work we do must function every day.\",\"iconName\":\"ShieldCheck\"},{\"title\":\"Real Impact\",\"description\":\"Employees contribute directly to systems that serve communities and support essential public operations.\",\"iconName\":\"Zap\"},{\"title\":\"Growth \\u0026 Development\",\"description\":\"Work alongside experienced professionals across infrastructure, security, applications, and strategy.\",\"iconName\":\"TrendingUp\"}]} /-->\n\n<!-- wp:xfact/code-embed {\"code\":\"<link rel=\\\"stylesheet\\\" type=\\\"text/css\\\" href=\\\"//reports.hrmdirect.com/employment/default/sm/settings/dynamic-embed/dynamic-iframe-embed-css.php\\\" />\\n<script type=\\\"text/javascript\\\" src=\\\"//reports.hrmdirect.com/employment/default/sm/settings/dynamic-embed/dynamic-iframe-embed-js.php\\\"></script>\\n<script>\\n  function resizeIframe(obj) {\\n    obj.style.height = obj.contentWindow.document.body.scrollHeight + \'px\';\\n  }\\n</script>\\n<iframe id=\\\"hrmdirect\\\" src=\\\"//dataserv.hrmdirect.com/employment/job-openings.php?search=true&nohd=&dept=-1&city=-1&state=-1\\\" style=\\\"width: 100%; height: 400px;\\\" frameborder=\\\"0\\\" scrolling=\\\"auto\\\" allowtransparency=\\\"true\\\" title=\\\"Career Site\\\"></iframe>\"} /-->\n\n<!-- wp:xfact/cta-section {\"variant\":\"dark\",\"align\":\"full\",\"title\":\"Interested in joining the team?\",\"subtitle\":\"We\'re always looking for talented people who want to do meaningful work.\",\"buttons\":[{\"label\":\"Get in Touch\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Careers', '', 'publish', 'closed', 'closed', '', 'careers', '', '', '2026-05-17 03:43:42', '2026-05-17 03:43:42', '', '0', 'https://xfact2stg.wpenginepowered.com/careers/', '0', 'page', '', '0'),
('8', '0', '2026-04-28 06:13:57', '2026-04-28 06:13:57', '<!-- wp:xfact/hero {\"sectionLabel\":\"Contact\",\"title\":\"Start the Conversation\",\"subtitle\":\"Complex environments require thoughtful evaluation.\",\"backgroundImage\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-contact.jpg\",\"imageAlt\":\"Kids using technology in the classroom\",\"align\":\"full\"} /-->\n\n<!-- wp:xfact/contact-form {\"heading\":\"Get in Touch\",\"subtitle\":\"Tell us about your organization and what you\'re looking to accomplish. We\'ll connect you with the right team.\",\"buttons\":[{\"label\":\"Request an Assessment\",\"url\":\"#assessment\",\"variant\":\"secondary\"}]} /-->', 'Contact', '', 'publish', 'closed', 'closed', '', 'contact', '', '', '2026-05-17 03:43:42', '2026-05-17 03:43:42', '', '0', 'https://xfact2stg.wpenginepowered.com/contact/', '0', 'page', '', '0'),
('9', '0', '2026-04-28 06:13:57', '2026-04-28 06:13:57', '<!-- wp:xfact/hero {\"sectionLabel\":\"Legal\",\"title\":\"Privacy Policy\",\"subtitle\":\"Effective date: January 1, 2025\",\"backgroundImage\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-contact.jpg\",\"imageAlt\":\"Privacy and security\",\"align\":\"full\"} /-->\n\n<!-- wp:xfact/section-list {\"showNumbers\":true,\"introText\":\"xFact (\\\"we,\\\" \\\"us,\\\" or \\\"our\\\") is committed to protecting the privacy of individuals who visit our website and use our services. This Privacy Policy describes how we collect, use, and safeguard your information.\",\"sections\":[{\"title\":\"Information We Collect\",\"content\":\"We collect information you provide directly, such as your name, email address, organization, and message content when you submit a contact form or request an assessment. We also automatically collect certain technical information when you visit our website, including your IP address, browser type, operating system, referring URLs, and pages viewed.\"},{\"title\":\"How We Use Your Information\",\"content\":\"We use the information we collect to respond to your inquiries and requests, provide and improve our services, communicate with you about our offerings, comply with legal obligations, and protect the security and integrity of our website and services.\"},{\"title\":\"Information Sharing\",\"content\":\"We do not sell, rent, or trade your personal information to third parties. We may share information with trusted service providers who assist us in operating our website and conducting our business, provided they agree to keep this information confidential. We may also disclose information when required by law or to protect our rights.\"},{\"title\":\"Data Security\",\"content\":\"We implement appropriate technical and organizational security measures to protect your personal information against unauthorized access, alteration, disclosure, or destruction. However, no method of transmission over the internet or electronic storage is completely secure, and we cannot guarantee absolute security.\"},{\"title\":\"Cookies and Tracking\",\"content\":\"Our website may use cookies and similar tracking technologies to enhance your browsing experience, analyze site traffic, and understand where our visitors come from. You can control cookie settings through your browser preferences. Disabling cookies may limit certain functionality of our website.\"},{\"title\":\"Third-Party Links\",\"content\":\"Our website may contain links to third-party websites. We are not responsible for the privacy practices or content of these external sites. We encourage you to review the privacy policies of any third-party sites you visit.\"},{\"title\":\"Data Retention\",\"content\":\"We retain your personal information only for as long as necessary to fulfill the purposes for which it was collected, comply with legal obligations, resolve disputes, and enforce our agreements.\"},{\"title\":\"Your Rights\",\"content\":\"You may request access to, correction of, or deletion of your personal information by contacting us. We will respond to your request within a reasonable timeframe and in accordance with applicable law.\"},{\"title\":\"Changes to This Policy\",\"content\":\"We may update this Privacy Policy from time to time. Changes will be posted on this page with an updated effective date. Your continued use of our website after any changes constitutes acceptance of the revised policy.\"},{\"title\":\"Contact Us\",\"content\":\"If you have questions about this Privacy Policy or our data practices, please contact us at info@xfact.com or through our contact page.\"}]} /-->', 'Privacy Policy', '', 'publish', 'closed', 'closed', '', 'privacy', '', '', '2026-05-17 03:43:44', '2026-05-17 03:43:44', '', '0', 'https://xfact2stg.wpenginepowered.com/privacy/', '0', 'page', '', '0'),
('10', '0', '2026-04-28 06:13:58', '2026-04-28 06:13:58', '<!-- wp:xfact/hero {\"sectionLabel\":\"Legal\",\"title\":\"Terms of Service\",\"subtitle\":\"Effective date: January 1, 2025\",\"backgroundImage\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-contact.jpg\",\"imageAlt\":\"Terms and conditions\",\"align\":\"full\"} /-->\n\n<!-- wp:xfact/section-list {\"showNumbers\":true,\"introText\":\"Please read these Terms of Service carefully before using the xFact website. These terms govern your access to and use of our website and services.\",\"sections\":[{\"title\":\"Acceptance of Terms\",\"content\":\"By accessing or using the xFact website, you agree to be bound by these Terms of Service and all applicable laws and regulations. If you do not agree with any of these terms, you are prohibited from using or accessing this site.\"},{\"title\":\"Use of Website\",\"content\":\"You may use our website for lawful purposes only. You agree not to use the site in any way that could damage, disable, overburden, or impair the site or interfere with any other party\'s use and enjoyment. You may not attempt to gain unauthorized access to any portion of the website, other accounts, computer systems, or networks connected to the website.\"},{\"title\":\"Intellectual Property\",\"content\":\"All content on this website, including text, graphics, logos, images, and software, is the property of xFact or its content suppliers and is protected by United States and international copyright, trademark, and other intellectual property laws. You may not reproduce, distribute, modify, or create derivative works from any content without our prior written consent.\"},{\"title\":\"Services Description\",\"content\":\"xFact provides technology services for public-sector organizations, including infrastructure management, cybersecurity, application development, data services, and strategic consulting. Descriptions of services on this website are for informational purposes only and do not constitute a binding offer or contract. Specific service terms are governed by individual client agreements.\"},{\"title\":\"Disclaimer of Warranties\",\"content\":\"This website and its content are provided on an \\\"as is\\\" and \\\"as available\\\" basis without warranties of any kind, either express or implied. xFact does not warrant that the website will be uninterrupted, error-free, or free of viruses or other harmful components. We make no warranties regarding the accuracy, reliability, or completeness of any content on this site.\"},{\"title\":\"Limitation of Liability\",\"content\":\"To the fullest extent permitted by applicable law, xFact shall not be liable for any indirect, incidental, special, consequential, or punitive damages arising out of or related to your use of or inability to use the website, even if we have been advised of the possibility of such damages. Our total liability for any claim arising from your use of the website shall not exceed the amount you paid, if any, for accessing the site.\"},{\"title\":\"Indemnification\",\"content\":\"You agree to indemnify and hold harmless xFact, its officers, directors, employees, and agents from any claims, damages, losses, liabilities, and expenses (including reasonable attorneys\' fees) arising out of or related to your use of the website or violation of these Terms of Service.\"},{\"title\":\"Third-Party Links\",\"content\":\"Our website may contain links to third-party websites or services that are not owned or controlled by xFact. We have no control over, and assume no responsibility for, the content, privacy policies, or practices of any third-party sites. You acknowledge and agree that xFact shall not be responsible or liable for any damage or loss caused by or in connection with the use of any third-party content or services.\"},{\"title\":\"Governing Law\",\"content\":\"These Terms of Service shall be governed by and construed in accordance with the laws of the United States, without regard to conflict of law provisions. Any disputes arising under these terms shall be subject to the exclusive jurisdiction of the courts in our principal place of business.\"},{\"title\":\"Changes to Terms\",\"content\":\"We reserve the right to modify these Terms of Service at any time. Changes will be effective immediately upon posting to this website. Your continued use of the website following any changes constitutes acceptance of the revised terms. We encourage you to review these terms periodically.\"},{\"title\":\"Contact\",\"content\":\"If you have any questions about these Terms of Service, please contact us at info@xfact.com or through our contact page.\"}]} /-->', 'Terms of Service', '', 'publish', 'closed', 'closed', '', 'terms', '', '', '2026-05-17 03:43:44', '2026-05-17 03:43:44', '', '0', 'https://xfact2stg.wpenginepowered.com/terms/', '0', 'page', '', '0'),
('18', '0', '2026-04-28 06:59:26', '2026-04-28 06:59:26', '<!-- wp:xfact/hero {\"sectionLabel\":\"About xFact\",\"title\":\"Behind the Systems Communities Rely On\",\"subtitle\":\"Since 2000, the teams behind xFact have partnered with public-sector institutions to design, integrate, secure, and sustain mission-critical technology systems.\"} /-->\n\n<!-- wp:xfact/text-section {\"sectionLabel\":\"Our Story\",\"heading\":\"Our Story\",\"body\":\"xFact began as a public-sector technology services firm focused on helping state, local, and education organizations modernize the systems their communities depend on. Over time, that work expanded across infrastructure, cybersecurity, applications, and strategy — building on and unifying capabilities from DataServ, which now operates as an xFact solution within the broader organization. Today, xFact serves as a single accountable partner for the institutions behind public safety, government, education, and human services.\"} /-->\n\n<!-- wp:xfact/text-section {\"sectionLabel\":\"Why We Do It\",\"heading\":\"Why We Do It\",\"body\":\"Public institutions rely on technology systems that must work every day. Many of those environments have evolved across multiple vendors, platforms, and legacy systems — creating fragmentation and operational risk. We exist to bring those environments together: integrated, accountable, and sustained over time so communities receive uninterrupted service.\"} /-->\n\n<!-- wp:xfact/feature-cards {\"sectionLabel\":\"How We Operate\",\"heading\":\"What partnership with xFact looks like\",\"cards\":[{\"title\":\"Long-term accountability\",\"description\":\"We stay with our clients across the full lifecycle of their systems — from design through ongoing operation.\",\"iconName\":\"ShieldCheck\"},{\"title\":\"One coordinated system\",\"description\":\"We bring infrastructure, security, applications, and strategy together so environments operate as one — not as a collection of disconnected services.\",\"iconName\":\"Network\"},{\"title\":\"Mission-aligned delivery\",\"description\":\"Every project we ship supports a public-sector mission. We build for reliability, governance, and the people communities depend on.\",\"iconName\":\"HeartPulse\"},{\"title\":\"Real partnership\",\"description\":\"We work alongside our clients, not at arm\'s length. That means clear communication, honest tradeoff conversations, and shared success metrics.\",\"iconName\":\"Users\"}]} /-->\n\n<!-- wp:xfact/cta-section {\"subtitle\":\"Whether you\'re planning an upgrade, evaluating a long-term partner, or starting an assessment — we\'re the right conversation to start.\",\"buttons\":[{\"label\":\"Contact xFact\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'About', '', 'publish', 'closed', 'closed', '', 'about', '', '', '2026-05-17 03:43:36', '2026-05-17 03:43:36', '', '0', 'https://xfact2stg.wpenginepowered.com/about/', '0', 'page', '', '0'),
('23', '1', '2026-04-28 07:49:00', '2026-04-28 07:49:00', '<!-- wp:xfact/hero {\"backgroundImage\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-solutions.jpg\",\"sectionLabel\":\"Capabilities\",\"title\":\"Integrated Capabilities for Mission-Critical Systems\",\"subtitle\":\"Coordinated expertise supporting systems across their full lifecycle — from idea to action, design through long-term operation.\",\"align\":\"full\"} /-->\n\n<!-- wp:xfact/text-section {\"sectionLabel\":\"Idea to Action\",\"heading\":\"A Full-Funnel Capabilities Stack\",\"body\":\"Public-sector environments require integrated expertise across infrastructure, security, applications, and strategy. xFact delivers coordinated, system-level solutions that align with governance and operational realities. Support extends from design through long-term operation.\"} /-->\n\n<!-- wp:xfact/capability-areas {\"areas\":[\n  {\"title\":\"Strategy & Advisory\",\"headline\":\"Where it starts: governance-aware strategy and planning that ensure systems evolve responsibly over time.\",\"body\":\"We help leaders shape technology direction in environments that demand stability, governance, and accountability. Our advisory work translates strategic intent into a practical roadmap that respects budget cycles, procurement rules, and the realities of running essential services.\",\"iconName\":\"Compass\",\"anchor\":\"strategy-advisory\",\"services\":[\"Technology assessments & roadmaps\",\"Architecture & enterprise planning\",\"Governance & risk strategy\",\"Procurement & vendor advisory\"]},\n  {\"title\":\"Applications & Integration\",\"headline\":\"Connected applications and systems designed to operate reliably as one coordinated environment.\",\"body\":\"We design, build, and integrate applications that connect across the systems public institutions already rely on. The result is fewer silos, less duplication, and a coordinated environment that scales with the mission.\",\"iconName\":\"AppWindow\",\"anchor\":\"applications-integration\",\"services\":[\"Custom application development\",\"System integration & APIs\",\"Workflow & case-management platforms\",\"Modernization of legacy applications\"]},\n  {\"title\":\"Data & Platforms\",\"headline\":\"Structured, secure data environments that enable visibility, coordination, and informed decision-making.\",\"body\":\"Our data work focuses on giving leaders a trustworthy picture of their environments. We build platforms that move sensitive data safely, structure it for accountability, and surface it where decisions are made.\",\"iconName\":\"Database\",\"anchor\":\"data-platforms\",\"services\":[\"Data platform design\",\"Reporting, analytics & dashboards\",\"Data governance & lineage\",\"Master data & integration patterns\"]},\n  {\"title\":\"Cybersecurity\",\"headline\":\"Coordinated protection and monitoring that keeps systems secure without disrupting essential operations.\",\"body\":\"Security in public-sector environments is a continuous practice, not a project. We design defenses that account for compliance requirements, monitor environments around the clock, and respond when something matters.\",\"iconName\":\"ShieldCheck\",\"anchor\":\"cybersecurity\",\"services\":[\"Security architecture & assessments\",\"Compliance (CJIS, HIPAA, FedRAMP, etc.)\",\"24x7 managed detection & response\",\"Incident response & recovery\"]},\n  {\"title\":\"Infrastructure & Platform Environments\",\"headline\":\"Resilient environments that ensure mission-critical systems remain secure, stable, and continuously operational.\",\"body\":\"Our infrastructure practice — delivered through DataServ, an xFact solution — provides the resilient foundation public institutions need to operate essential systems with confidence.\",\"iconName\":\"ServerCog\",\"anchor\":\"infrastructure\",\"services\":[\"Hybrid & cloud infrastructure\",\"Hosted platform environments (DataServ)\",\"Network & telecommunications\",\"Managed services & monitoring\"]}\n]} /-->\n\n<!-- wp:xfact/cta-section {\"variant\":\"light\",\"align\":\"full\",\"title\":\"Bring it all together.\",\"subtitle\":\"Talk to us about coordinating your environments under one accountable partner.\",\"buttons\":[{\"label\":\"Start a conversation\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Capabilities', '', 'publish', 'closed', 'closed', '', 'capabilities', '', '', '2026-05-17 03:43:36', '2026-05-17 03:43:36', '', '0', 'https://xfact2stg.wpenginepowered.com/capabilities/', '0', 'page', '', '0'),
('33', '0', '2026-04-28 13:14:01', '2026-04-28 13:14:01', '<!-- wp:xfact/hero {\"backgroundImage\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/hero-contact.jpg\",\"sectionLabel\":\"News \\u0026 Insights\",\"title\":\"News \\u0026 Insights\",\"subtitle\":\"Perspectives on public-sector systems and the technology behind them.\",\"align\":\"full\"} /-->\n\n<!-- wp:xfact/text-section {\"sectionLabel\":\"Stories from xFact\",\"body\":\"Technology environments continue to evolve. We publish field-level insights on what we see across public safety, government, education, and human services — grounded in real-world engagements rather than vendor talking points.\"} /-->\n\n<!-- wp:xfact/text-section {\"useAltBackground\":true,\"isCenteredCard\":true,\"sectionLabel\":\"New stories on the way\",\"heading\":\"Stay Tuned\",\"body\":\"We\'re reorganizing the DataServ archive into a unified news feed. Check back shortly — or reach out if you\'d like to talk to us in the meantime.\"} /-->\n\n<!-- wp:xfact/cta-section {\"variant\":\"light\",\"align\":\"full\",\"title\":\"Want to talk shop?\",\"subtitle\":\"We share insights privately, too. Reach out and we can dive in on your environment.\",\"buttons\":[{\"label\":\"Contact us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'News & Insights', '', 'publish', 'closed', 'closed', '', 'news', '', '', '2026-05-17 03:43:37', '2026-05-17 03:43:37', '', '0', 'https://xfact2stg.wpenginepowered.com/news/', '0', 'page', '', '0'),
('34', '0', '2026-04-28 13:14:03', '2026-04-28 13:14:03', '<!-- wp:xfact/hero {\"title\":\"Strengthening Systems That Cannot Fail\",\"subtitle\":\"Supporting real-time operations where reliability is critical.\",\"bodyText\":\"Public safety agencies operate in environments where technology reliability is critical to real-time operations. Communications infrastructure and secure information environments must remain continuously available while meeting stringent security and compliance requirements.\",\"useBreadcrumbs\":true,\"align\":\"full\"} /-->\n\n<!-- wp:xfact/text-section {\"sectionIcon\":\"Shield\",\"sectionLabel\":\"Public Safety \\u0026 Justice\",\"body\":\"xFact helps public safety organizations maintain resilient and secure technology environments that support mission-critical operations and ensure systems remain dependable in high-consequence situations.\",\"keyMessages\":[\"Public safety systems operate in high-consequence environments.\",\"Systems must meet strict security and compliance requirements.\",\"xFact ensures systems remain secure, integrated, and continuously available.\",\"Coordinated systems support dependable public safety outcomes.\"]} /-->\n\n<!-- wp:xfact/case-study-grid {\"sectionLabel\":\"Case Studies\",\"heading\":\"Proof in Public Safety\",\"description\":\"Engagements where xFact has helped public-sector teams strengthen the systems behind their work.\",\"items\":[{\"title\":\"Public Safety Data Broker Solution\",\"linkUrl\":\"/case-studies/public-safety-data-broker/\"},{\"title\":\"License Management System\",\"linkUrl\":\"/case-studies/license-management-system/\"},{\"title\":\"Cloud Migration Strategic Roadmap\",\"linkUrl\":\"/case-studies/cloud-migration-strategic-roadmap/\"}]} /-->\n\n<!-- wp:xfact/navigation-cards {\"heading\":\"Relevant Capabilities\",\"items\":[{\"title\":\"Cybersecurity\",\"subtitle\":\"Proactive defense for sensitive environments.\",\"icon\":\"ShieldCheck\",\"href\":\"/capabilities#cybersecurity\"},{\"title\":\"Infrastructure \\u0026 Platform Environments\",\"subtitle\":\"Resilient environments for mission-critical systems.\",\"icon\":\"ServerCog\",\"href\":\"/capabilities#infrastructure\"},{\"title\":\"Applications \\u0026 Integration\",\"subtitle\":\"Connecting systems for unified operations.\",\"icon\":\"AppWindow\",\"href\":\"/capabilities#applications-integration\"}],\"buttons\":[{\"label\":\"See all capabilities →\",\"url\":\"/capabilities\",\"variant\":\"secondary\"}]} /-->\n\n<!-- wp:xfact/navigation-cards {\"sectionLabel\":\"MORE INDUSTRIES\",\"heading\":\"Other systems we support\",\"items\":[{\"title\":\"Municipal, State & Local Government\",\"icon\":\"Landmark\",\"href\":\"/solutions/government\"},{\"title\":\"Education\",\"icon\":\"GraduationCap\",\"href\":\"/solutions/education\"},{\"title\":\"Health & Human Services\",\"icon\":\"HeartPulse\",\"href\":\"/solutions/health-and-human-services\"},{\"title\":\"Infrastructure & Managed Services\",\"icon\":\"ServerCog\",\"href\":\"/solutions/infrastructure\"}],\"buttons\":[]} /-->\n\n<!-- wp:xfact/cta-section {\"align\":\"full\",\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Public Safety & Justice', '', 'publish', 'closed', 'closed', '', 'public-safety', '', '', '2026-05-17 03:43:38', '2026-05-17 03:43:38', '', '5', 'https://xfact2stg.wpenginepowered.com/solutions/public-safety/', '0', 'page', '', '0'),
('35', '0', '2026-04-28 13:14:03', '2026-04-28 13:14:03', '<!-- wp:xfact/hero {\"title\":\"Coordinating Systems That Support Communities\",\"subtitle\":\"Supporting reliable technology environments across government operations.\",\"bodyText\":\"State, municipal, and county governments rely on interconnected systems that support essential community services. From public works and administrative operations to digital services and civic infrastructure, these systems must remain secure, resilient, and continuously operational.\",\"useBreadcrumbs\":true,\"align\":\"full\"} /-->\n\n<!-- wp:xfact/text-section {\"sectionIcon\":\"Landmark\",\"sectionLabel\":\"Municipal, State \\u0026 Local Government\",\"body\":\"xFact helps state and local governments strengthen and coordinate these technology environments so departments can operate reliably, manage growing complexity, and sustain the services communities depend on.\",\"keyMessages\":[\"Government systems must operate reliably across departments and services.\",\"Fragmentation and governance requirements increase complexity.\",\"xFact integrates and modernizes systems while maintaining stability.\",\"Long-term partnership supports consistent service delivery.\"]} /-->\n\n<!-- wp:xfact/case-study-grid {\"sectionLabel\":\"Case Studies\",\"heading\":\"Proof in Municipal, State\",\"description\":\"Engagements where xFact has helped public-sector teams strengthen the systems behind their work.\",\"items\":[{\"title\":\"Enterprise Risk Management Plan\",\"linkUrl\":\"/case-studies/enterprise-risk-management-plan/\"},{\"title\":\"Hybrid Cloud Data Center Migration\",\"linkUrl\":\"/case-studies/hybrid-cloud-data-center-migration/\"},{\"title\":\"Covid19 and Collaboration\",\"linkUrl\":\"/case-studies/covid-19-collaboration-remote-work-enablement/\"}]} /-->\n\n<!-- wp:xfact/navigation-cards {\"heading\":\"Relevant Capabilities\",\"items\":[{\"title\":\"Infrastructure \\u0026 Platform Environments\",\"subtitle\":\"Resilient environments for mission-critical systems.\",\"icon\":\"ServerCog\",\"href\":\"/capabilities#infrastructure\"},{\"title\":\"Data \\u0026 Analytics Platforms\",\"subtitle\":\"Actionable insights from complex data.\",\"icon\":\"Database\",\"href\":\"/capabilities#data-platforms\"},{\"title\":\"Strategy \\u0026 Advisory\",\"subtitle\":\"Aligning technology with operational goals.\",\"icon\":\"Compass\",\"href\":\"/capabilities#strategy-advisory\"}],\"buttons\":[{\"label\":\"See all capabilities →\",\"url\":\"/capabilities\",\"variant\":\"secondary\"}]} /-->\n\n<!-- wp:xfact/navigation-cards {\"sectionLabel\":\"MORE INDUSTRIES\",\"heading\":\"Other systems we support\",\"items\":[{\"title\":\"Public Safety & Justice\",\"icon\":\"Shield\",\"href\":\"/solutions/public-safety\"},{\"title\":\"Education\",\"icon\":\"GraduationCap\",\"href\":\"/solutions/education\"},{\"title\":\"Health & Human Services\",\"icon\":\"HeartPulse\",\"href\":\"/solutions/health-and-human-services\"},{\"title\":\"Infrastructure & Managed Services\",\"icon\":\"ServerCog\",\"href\":\"/solutions/infrastructure\"}],\"buttons\":[]} /-->\n\n<!-- wp:xfact/cta-section {\"align\":\"full\",\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Municipal, State & Local Government', '', 'publish', 'closed', 'closed', '', 'government', '', '', '2026-05-17 03:43:39', '2026-05-17 03:43:39', '', '5', 'https://xfact2stg.wpenginepowered.com/solutions/government/', '0', 'page', '', '0'),
('36', '0', '2026-04-28 13:14:04', '2026-04-28 13:14:04', '<!-- wp:xfact/hero {\"title\":\"Supporting Learning Through Reliable Systems\",\"subtitle\":\"Helping K-12 schools maintain secure, stable technology environments.\",\"bodyText\":\"Educational institutions manage interconnected systems that range from student information and learning management to operational infrastructure.\",\"useBreadcrumbs\":true,\"align\":\"full\"} /-->\n\n<!-- wp:xfact/text-section {\"sectionIcon\":\"GraduationCap\",\"sectionLabel\":\"Education\",\"body\":\"xFact helps school systems maintain stable, secure infrastructure that supports educators, protects student data, and enables technology environments to evolve responsibly without disrupting the learning experience.\",\"keyMessages\":[\"Schools rely on systems for instruction, operations, and student services.\",\"Systems must remain available while adapting to evolving needs.\",\"xFact supports secure, reliable environments that protect student data.\",\"Technology evolves without disrupting learning experiences.\"]} /-->\n\n<!-- wp:xfact/navigation-cards {\"heading\":\"Relevant Capabilities\",\"items\":[{\"title\":\"Infrastructure \\u0026 Platform Environments\",\"subtitle\":\"Resilient environments for mission-critical systems.\",\"icon\":\"ServerCog\",\"href\":\"/capabilities#infrastructure\"},{\"title\":\"Cybersecurity\",\"subtitle\":\"Proactive defense for sensitive environments.\",\"icon\":\"ShieldCheck\",\"href\":\"/capabilities#cybersecurity\"},{\"title\":\"Applications \\u0026 Integration\",\"subtitle\":\"Connecting systems for unified operations.\",\"icon\":\"AppWindow\",\"href\":\"/capabilities#applications-integration\"}],\"buttons\":[{\"label\":\"See all capabilities →\",\"url\":\"/capabilities\",\"variant\":\"secondary\"}]} /-->\n\n<!-- wp:xfact/navigation-cards {\"sectionLabel\":\"MORE INDUSTRIES\",\"heading\":\"Other systems we support\",\"items\":[{\"title\":\"Public Safety & Justice\",\"icon\":\"Shield\",\"href\":\"/solutions/public-safety\"},{\"title\":\"Municipal, State & Local Government\",\"icon\":\"Landmark\",\"href\":\"/solutions/government\"},{\"title\":\"Health & Human Services\",\"icon\":\"HeartPulse\",\"href\":\"/solutions/health-and-human-services\"},{\"title\":\"Infrastructure & Managed Services\",\"icon\":\"ServerCog\",\"href\":\"/solutions/infrastructure\"}],\"buttons\":[]} /-->\n\n<!-- wp:xfact/cta-section {\"align\":\"full\",\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Education', '', 'publish', 'closed', 'closed', '', 'education', '', '', '2026-05-17 03:43:39', '2026-05-17 03:43:39', '', '5', 'https://xfact2stg.wpenginepowered.com/solutions/education/', '0', 'page', '', '0'),
('46', '0', '2026-04-28 14:17:38', '2026-04-28 14:17:38', '<!-- wp:xfact/hero {\"title\":\"Resilient Infrastructure for Mission-Critical Systems\",\"bodyText\":\"We provide secure infrastructure environments designed to support the continuous operation of mission-critical public systems, delivering the stability, performance, and security required in high-accountability environments.\",\"badgeText\":\"DataServ, an xFact solution\",\"useBreadcrumbs\":true,\"align\":\"full\"} /-->\n\n<!-- wp:xfact/text-section {\"sectionIcon\":\"ServerCog\",\"sectionLabel\":\"Infrastructure \\u0026 Managed Services\",\"badgeText\":\"DataServ, an xFact solution\",\"body\":\"We provide secure infrastructure environments designed to support the continuous operation of mission-critical public systems, delivering the stability, performance, and security required in high-accountability environments.\",\"keyMessages\":[\"Mission-critical systems require continuously available platforms.\",\"High-accountability environments demand stability, performance, and security.\",\"Resilient foundations support responsible modernization over time.\",\"A single accountable partner reduces operational risk.\"]} /-->\n\n<!-- wp:xfact/navigation-cards {\"heading\":\"Relevant Capabilities\",\"items\":[{\"title\":\"Infrastructure \\u0026 Platform Environments\",\"subtitle\":\"Resilient environments for mission-critical systems.\",\"icon\":\"ServerCog\",\"href\":\"/capabilities#infrastructure\"},{\"title\":\"Cybersecurity\",\"subtitle\":\"Proactive defense for sensitive environments.\",\"icon\":\"ShieldCheck\",\"href\":\"/capabilities#cybersecurity\"}],\"buttons\":[{\"label\":\"See all capabilities →\",\"url\":\"/capabilities\",\"variant\":\"secondary\"}]} /-->\n\n<!-- wp:xfact/navigation-cards {\"sectionLabel\":\"MORE INDUSTRIES\",\"heading\":\"Other systems we support\",\"items\":[{\"title\":\"Public Safety & Justice\",\"icon\":\"Shield\",\"href\":\"/solutions/public-safety\"},{\"title\":\"Municipal, State 