('116', '0', '2026-04-30 08:21:46', '2026-04-30 08:21:46', '<!-- wp:xfact/hero {\"title\":\"Supporting Systems That Serve Communities\",\"subtitle\":\"Strengthening systems that support critical programs and services.\",\"bodyText\":\"Health and human services agencies manage systems that must simultaneously ensure accessibility for constituents and comply with stringent privacy requirements.\",\"useBreadcrumbs\":true,\"align\":\"full\"} /-->\n\n<!-- wp:xfact/text-section {\"sectionIcon\":\"HeartPulse\",\"sectionLabel\":\"Health \\u0026 Human Services\",\"body\":\"xFact helps health and human services agencies maintain stable, secure technology environments that support essential programs, protect sensitive information, and ensure systems operate reliably in complex regulatory environments.\",\"keyMessages\":[\"HHS systems support essential services for individuals and communities.\",\"Systems must balance accessibility, privacy, and compliance.\",\"xFact ensures systems remain secure, stable, and reliable.\",\"Long-term partnership supports sustained program delivery.\"]} /-->\n\n<!-- wp:xfact/case-study-grid {\"sectionLabel\":\"Case Studies\",\"heading\":\"Proof in Health\",\"description\":\"Engagements where xFact has helped public-sector teams strengthen the systems behind their work.\",\"items\":[{\"title\":\"HHS Child Welfare Case Management System Modernization\",\"linkUrl\":\"/case-studies/hhs-child-welfare-case-management-system-modernization/\"},{\"title\":\"Healthcare Operations Optimization\",\"linkUrl\":\"/case-studies/healthcare/\"}]} /-->\n\n<!-- wp:xfact/navigation-cards {\"heading\":\"Relevant Capabilities\",\"items\":[{\"title\":\"Cybersecurity\",\"subtitle\":\"Proactive defense for sensitive environments.\",\"icon\":\"ShieldCheck\",\"href\":\"/capabilities#cybersecurity\"},{\"title\":\"Data \\u0026 Analytics Platforms\",\"subtitle\":\"Actionable insights from complex data.\",\"icon\":\"Database\",\"href\":\"/capabilities#data-platforms\"},{\"title\":\"Applications \\u0026 Integration\",\"subtitle\":\"Connecting systems for unified operations.\",\"icon\":\"AppWindow\",\"href\":\"/capabilities#applications-integration\"}],\"buttons\":[{\"label\":\"See all capabilities →\",\"url\":\"/capabilities\",\"variant\":\"secondary\"}]} /-->\n\n<!-- wp:xfact/navigation-cards {\"sectionLabel\":\"MORE INDUSTRIES\",\"heading\":\"Other systems we support\",\"items\":[{\"title\":\"Public Safety & Justice\",\"icon\":\"Shield\",\"href\":\"/solutions/public-safety\"},{\"title\":\"Municipal, State & Local Government\",\"icon\":\"Landmark\",\"href\":\"/solutions/government\"},{\"title\":\"Education\",\"icon\":\"GraduationCap\",\"href\":\"/solutions/education\"},{\"title\":\"Infrastructure & Managed Services\",\"icon\":\"ServerCog\",\"href\":\"/solutions/infrastructure\"}],\"buttons\":[]} /-->\n\n<!-- wp:xfact/cta-section {\"align\":\"full\",\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Health & Human Services', '', 'publish', 'closed', 'closed', '', 'health-and-human-services', '', '', '2026-05-17 03:43:40', '2026-05-17 03:43:40', '', '5', 'https://xfact2stg.wpenginepowered.com/solutions/health-and-human-services/', '0', 'page', '', '0'),
('133', '0', '2026-04-30 12:27:16', '2026-04-30 12:27:16', '<!-- wp:xfact/hero {\"sectionLabel\": \"Case Studies\", \"title\": \"Public Safety Data Broker Solution\", \"subtitle\": \"A high-volume, fault-tolerant message broker enabling standardized criminal-justice information sharing across state, federal, and international systems.\", \"align\": \"full\"} /-->\n\n<!-- wp:xfact/case-study-details {\"summary\":\"Coordinated data brokerage platform connecting law-enforcement systems while preserving security and compliance.\",\"source\":\"xFact\",\"client\": \"State-wide Criminal Justice Information Services Agency\", \"challenge\": [\"Facilitate a standardized way of sharing disparate criminal justice information across systems.\", \"Interface with multiple state, federal, and international data sources while avoiding API explosion and ensuring data-driven transactions could be handled efficiently.\", \"Provide high-volume message handling, guaranteed secure message delivery, and mission-critical system performance and reliability.\"], \"services\": [\"Collaboratively planned and designed/architected a component-based solution that emphasized scalability, fault tolerance, and security.\", \"Rapidly implemented a high-volume, high-performance message broker with intelligent header-based message formatting and guaranteed delivery.\", \"Incorporated comprehensive advanced security protocols to ensure message integrity and confidentiality, including end-to-end encryption and secure access controls.\", \"Leveraged state-of-the-art technologies to ensure the system could scale to handle transaction bursts while maintaining a minimal memory footprint.\"], \"outcomes\": [\"Provided standards-based integration of multiple state, federal, and international data sources.\", \"Successfully processing over 2.5 million transactions daily, with the capability to handle bursts of up to 5 million transactions, ensuring timely access to critical criminal justice information.\", \"Guaranteed secure message delivery with a highly fault-tolerant architecture, significantly reducing the risk of data breaches and system downtime.\", \"Streamlined operations, reducing complexity and enhancing efficiency for law enforcement agencies.\"], \"narrative\": \"xFact\\u2019s Public Safety Data Broker Solution exemplifies cutting-edge technology application in public safety, demonstrating our firm\\u2019s commitment to developing solutions that meet the critical needs of law enforcement agencies. Through strategic planning, technical excellence, and a focus on security and scalability, we have delivered a system that not only meets but exceeds the expectations of our client, paving the way for safer communities through improved information sharing.\"} /-->\n\n<!-- wp:xfact/cta-section {\"align\":\"full\",\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Public Safety Data Broker Solution', '', 'publish', 'closed', 'closed', '', 'public-safety-data-broker', '', '', '2026-05-17 03:43:50', '2026-05-17 03:43:50', '', '0', 'https://xfact2stg.wpenginepowered.com/case-studies/public-safety-data-broker/', '0', 'case_study', '', '0'),
('134', '0', '2026-04-30 12:27:18', '2026-04-30 12:27:18', '<!-- wp:xfact/hero {\"sectionLabel\": \"Case Studies\", \"title\": \"License Management System\", \"subtitle\": \"A modular firearms-licensing platform rolled out across 350+ local police departments and all state-licensed firearms dealers \\u2014 the first solution of its kind in the USA.\", \"align\": \"full\"} /-->\n\n<!-- wp:xfact/case-study-details {\"summary\":\"Modernized licensing workflows for a state public-safety agency, replacing legacy paper-based processes with secure digital ones.\",\"source\":\"xFact\",\"client\": \"State-wide Firearms Licensing Agency\", \"challenge\": [\"Plan, test, and implement a mission-critical roll-out to comply with legal requirements for firearms licensing.\", \"Satisfy diverse end-user training requirements and change management needs to ensure successful transition from paper/manual processes to a fully electronic model.\", \"Maintain and synchronize legacy system in parallel with phased roll-out of new platform.\"], \"services\": [\"Modularized License Management System platform.\", \"Re-usable testing processes, protocols, and tools to ensure compliance with all business and legal requirements.\", \"Data migration and synchronization with legacy system.\", \"Comprehensive training programs and materials for various types of end-users, operational managers, and support personnel.\", \"\\u201cRoadshow\\u201d style training and deployments to engage stakeholders and ensure implementation success.\"], \"outcomes\": [\"Successfully implemented all deployments and go-live phases across over 350 local police departments and all state-licensed firearms dealers.\", \"Mitigated risks and expectations for service levels to ensure a smooth deployment and trust in the new system.\", \"Recognized as an innovative government solution and the first solution of its kind deployed in the USA.\", \"Successfully facilitated funding for additional enhancements and phases.\"]} /-->\n\n<!-- wp:xfact/cta-section {\"align\":\"full\",\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'License Management System', '', 'publish', 'closed', 'closed', '', 'license-management-system', '', '', '2026-05-17 03:43:51', '2026-05-17 03:43:51', '', '0', 'https://xfact2stg.wpenginepowered.com/case-studies/license-management-system/', '0', 'case_study', '', '0'),
('135', '0', '2026-04-30 12:27:20', '2026-04-30 12:27:20', '<!-- wp:xfact/hero {\"sectionLabel\": \"Case Studies\", \"title\": \"Cloud Migration Strategic Roadmap\", \"subtitle\": \"A comprehensive cloud migration roadmap and serverless architecture recommendations for a major criminal-justice agency, meeting FedRAMP High and CJIS compliance.\", \"align\": \"full\"} /-->\n\n<!-- wp:xfact/case-study-details {\"summary\":\"A phased cloud-migration plan that preserved real-time availability for mission-critical public-safety operations.\",\"source\":\"xFact\",\"client\": \"Major Public Sector Criminal Justice Agency\", \"challenge\": [\"Delivering a comprehensive cloud migration approach and recommendations to support hybrid connectivity and a move towards a serverless architecture, balancing the need to maintain legacy systems with the advantages of cloud-based solutions.\", \"Identifying recommendations around robust security measures, including multi-factor authentication and a comprehensive backup and recovery strategy, to protect sensitive criminal justice information.\", \"Accurately evaluating the current infrastructure, including virtual machines, physical servers, and critical software components like ETL and SSIS packages, to understand the baseline and identify areas for improvement.\", \"Ensuring government cloud compliance via a new system architecture complied with stringent government cloud standards, including FedRAMP High and CJIS Security Policy, while migrating to a cloud-based solution.\"], \"services\": [\"Established an enterprise architecture assessment through a review of the existing system infrastructure(s) and dependencies to identify opportunities for modernization and enhancement.\", \"Utilized industry-leading frameworks to design a resilient, highly available cloud migration strategy and infrastructure that meets government compliance requirements, focusing on a serverless, low-maintenance architecture that simplifies ongoing operations.\", \"Developed a networking and infrastructure plan that supports both cloud and hybrid environments, ensuring secure, efficient connectivity for all users.\", \"Outlined government cloud-based identity management solutions and migration recommendations to support seamless integration and continued compliance with security standards.\"], \"outcomes\": [\"Provided comprehensive recommendations for a highly available, resilient, and reliable architecture by implementing best practices for designing a highly available cloud infrastructure.\", \"Delivered a migration roadmap describing the requirements (business, technical, quality, security, etc.) for migrating the agency\\u2019s system(s) to the Cloud, including the recommended tools that shall be used in the migration.\", \"Provided a final report and set of recommendations to senior leadership and executive sponsors research, evaluation, findings, risks assessment and recommendations for the proposed cloud solution.\"]} /-->\n\n<!-- wp:xfact/cta-section {\"align\":\"full\",\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Cloud Migration Strategic Roadmap', '', 'publish', 'closed', 'closed', '', 'cloud-migration-strategic-roadmap', '', '', '2026-05-17 03:43:51', '2026-05-17 03:43:51', '', '0', 'https://xfact2stg.wpenginepowered.com/case-studies/cloud-migration-strategic-roadmap/', '0', 'case_study', '', '0'),
('159', '0', '2026-05-11 16:17:28', '2026-05-11 16:17:28', '<!-- wp:xfact/hero {\"sectionLabel\":\"Leadership\",\"title\":\"Our Leadership\",\"subtitle\":\"Guiding our mission to support public sector organizations through technology.\",\"align\":\"full\"} /-->\n\n<!-- wp:xfact/team-grid {\"sectionLabel\":\"Executive Team\",\"heading\":\"Leading with Purpose\",\"teamMembers\":[{\"name\":\"Jeff Valentine\",\"title\":\"Chief Executive Officer\",\"imageUrl\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/leadership/jeff-valentine.jpg\",\"socialLinks\":[{\"type\":\"linkedin\",\"url\":\"https://linkedin.com/in/jeff-valentine-7b67817\"}]},{\"name\":\"Tim Heikkila\",\"title\":\"Sr. VP of Sales and Marketing\",\"imageUrl\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/leadership/tim-heikkila.jpeg\",\"socialLinks\":[]},{\"name\":\"Grayson Harcourt\",\"title\":\"Chief Financial Officer\",\"imageUrl\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/leadership/grayson-harcourt.jpeg\",\"socialLinks\":[]},{\"name\":\"Dave Jacobson\",\"title\":\"VP of Services\",\"imageUrl\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/leadership/dave-jacobson.jpeg\",\"socialLinks\":[]},{\"name\":\"Karen Knaack\",\"title\":\"Sr. VP of Administration\",\"imageUrl\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/leadership/karen-knaack.jpeg\",\"socialLinks\":[]},{\"name\":\"Richard Gee\",\"title\":\"Principal, Technology Architecture\",\"imageUrl\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/leadership/richard-gee.jpeg\",\"socialLinks\":[{\"type\":\"linkedin\",\"url\":\"https://linkedin.com/in/richard-gee-nyc\"}]},{\"name\":\"Sean Hughes\",\"title\":\"Principal, Public Safety and Justice\",\"imageUrl\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/leadership/sean-hughes.jpg\",\"socialLinks\":[{\"type\":\"linkedin\",\"url\":\"https://www.linkedin.com/in/seanmichaelhughes/\"}]},{\"name\":\"Paul Connelly\",\"title\":\"Principal, State and Local Government Consulting\",\"imageUrl\":\"https://xfact2stg.wpenginepowered.com/wp-content/themes/xfact/assets/images/leadership/paul-connelly.jpg\",\"socialLinks\":[{\"type\":\"linkedin\",\"url\":\"https://linkedin.com/in/paul-connelly-72486517\"}]}]} /-->\n\n<!-- wp:xfact/cta-section {\"align\":\"full\",\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Leadership', '', 'publish', 'closed', 'closed', '', 'leadership', '', '', '2026-05-17 03:43:43', '2026-05-17 03:43:43', '', '0', 'https://xfact2stg.wpenginepowered.com/leadership/', '0', 'page', '', '0'),
('167', '0', '2026-05-12 14:20:35', '2026-05-12 14:20:35', '<!-- wp:xfact/hero {\"sectionLabel\":\"Case Studies\",\"title\":\"Enterprise Risk Management Plan\",\"subtitle\":\"Risk Management Office of a State-wide IT Agency\"} /-->\n\n<!-- wp:xfact/case-study-details {\"summary\":\"Built a scalable ERM program for a growing state-wide IT agency, enabling consistent risk oversight, regulatory compliance, and informed decision-making across newly integrated units.\",\"source\":\"xFact\",\"client\":\"Major Public Sector Criminal Justice Agency\",\"challenge\":[\"Create an ERM framework for a newly-established Enterprise Risk Management Office (ERMO)\",\"Provide continuity of implementation across an organization undergoing significant growth and transformation, including consolidation of units from other government agencies\",\"Educate business units across the enterprise on new ERM program\"],\"services\":[\"C-level client interaction, management and reporting\",\"Program development and support to Chief Risk Officer and ERMO\",\"Risk assessment workshops\",\"Development of actionable strategic recommendations to realize “to be” goals, including funding requirements\"],\"outcomes\":[\"Established foundational ERM framework\",\"Completed comprehensive Internal Control Plan for regulatory review\",\"Developed organizational and departmental Risk Appetite Statement documents\",\"Implemented enterprise-wide Risk Register\",\"Implemented ERM policy framework\"]} /-->\n\n<!-- wp:xfact/cta-section {\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Enterprise Risk Management Plan', '', 'publish', 'closed', 'closed', '', 'enterprise-risk-management-plan', '', '', '2026-05-17 03:43:52', '2026-05-17 03:43:52', '', '0', 'https://xfact2stg.wpenginepowered.com/case-studies/enterprise-risk-management-plan/', '0', 'case_study', '', '0'),
('168', '0', '2026-05-12 14:20:35', '2026-05-12 14:20:35', '<!-- wp:xfact/hero {\"sectionLabel\":\"Case Studies\",\"title\":\"Hybrid Cloud Data Center Migration\",\"subtitle\":\"Major State-wide IT Agency\\\n\"} /-->\n\n<!-- wp:xfact/case-study-details {\"summary\":\"Enabled a cost-effective transition to a hybrid and multi-cloud environment for a state-wide IT agency, modernizing application infrastructure while maintaining operational continuity, improving security, and supporting future scalability.\",\"source\":\"xFact\",\"client\":\"Major State-wide IT Agency\",\"challenge\":[\"Plan and implement cost-sensitive modernization efforts while also providing continuity of operations\",\"Identify multi-cloud solutions that reduce operational and technical complexity while enhancing security (mitigation of malware,ransomware, disaster recovery, etc.)\",\"Leverage existing assets while supporting future-forward infrastructure and development efforts\"],\"services\":[\"Engagement of technical and C-level stakeholders to define strategic goals for application portfolio modernization\",\"Development and analysis of detailed application portfolio inventories and critical path actions for modernization\",\"Architecting of cloud, multi-cloud, and hybrid-cloud options to fit client needs\",\"Implementation of IaaS and DaaS solutions\"],\"outcomes\":[\"Developed Enterprise Technical Standards (ETS) for app. portfolio modernization and cloud migration\",\"Facilitated an IaaS-based data center migration plan and implementation framework\",\"Established a cloud/multi-cloud/hybrid-cloud migration architecture\",\"Implemented IaaS, DaaS, and PaaS technical environments for application data center migration\"]} /-->\n\n<!-- wp:xfact/cta-section {\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Hybrid Cloud Data Center Migration', '', 'publish', 'closed', 'closed', '', 'hybrid-cloud-data-center-migration', '', '', '2026-05-17 03:43:52', '2026-05-17 03:43:52', '', '0', 'https://xfact2stg.wpenginepowered.com/case-studies/hybrid-cloud-data-center-migration/', '0', 'case_study', '', '0'),
('169', '0', '2026-05-12 14:20:36', '2026-05-12 14:20:36', '<!-- wp:xfact/hero {\"sectionLabel\":\"Case Studies\",\"title\":\"Covid19 and Collaboration \",\"subtitle\":\"Enabled seamless remote work transition during COVID-19 by leveraging secure collaboration tools and ensuring uninterrupted business continuity across the organization.\"} /-->\n\n<!-- wp:xfact/case-study-details {\"summary\":\"Enabled DataServ to rapidly transition to a remote workforce during the COVID-19 crisis by leveraging an established collaboration framework, ensuring business continuity, secure operations, and uninterrupted client support.\",\"source\":\"Dataserv\",\"client\":\"DataServ\",\"challenge\":[\"Rapidly transition to a remote work environment during the COVID-19 pandemic while maintaining business continuity and productivity.\",\"Adapt existing continuity plans to support large-scale remote collaboration and secure operations.\",\"Ensure seamless communication, workflow efficiency, and employee connectivity without disruption.\"],\"services\":[\"Executed a well-established Emergency Response Plan to quickly enable remote operations.\",\"Leveraged existing collaborative infrastructure including VPN, secure email, multi-factor authentication, and video conferencing tools.\",\"Assessed employee workflows and pain points to optimize collaboration and productivity.\",\"Strengthened secure access, communication systems, and process efficiency across distributed teams.\"],\"outcomes\":[\"Successfully transitioned over 90% of the workforce to remote operations with no business disruption.\",\"Maintained secure, efficient, and scalable collaboration across the organization.\",\"Enhanced productivity and operational resilience through a strong collaboration framework.\",\"Enabled continued client support and service delivery during a global crisis.\"],\"narrative\":\"A collaborative mindset and culture go beyond a collaboration solution. It is the assessment and planning before the implementation that truly makes the difference. Our people and our processes laid the foundation of our company’s collaborative culture and infrastructure. We assessed our team member’s pain points, evaluated their workflows, and sought to implement a collaborative framework using technology that would allow an increase in efficiency and productivity.\"} /-->\n\n<!-- wp:xfact/cta-section {\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'COVID-19 Collaboration & Remote Work Enablement', '', 'publish', 'closed', 'closed', '', 'covid-19-collaboration-remote-work-enablement', '', '', '2026-05-17 03:43:53', '2026-05-17 03:43:53', '', '0', 'https://xfact2stg.wpenginepowered.com/case-studies/covid-19-collaboration-remote-work-enablement/', '0', 'case_study', '', '0'),
('170', '0', '2026-05-12 14:20:36', '2026-05-12 14:20:36', '<!-- wp:xfact/hero {\"sectionLabel\":\"Case Studies\",\"title\":\"Healthcare\",\"subtitle\":\"Modernized healthcare IT infrastructure for Ohio Masonic Home, enabling a secure, scalable in-house environment that improved operational efficiency and supported long-term digital transformation.\"} /-->\n\n<!-- wp:xfact/case-study-details {\"summary\":\"Operational and infrastructure improvements for a regional healthcare provider, focused on reliability and continuous availability.\",\"source\":\"DataServ\",\"client\":\"Ohio Masonic Home\",\"challenge\":[\"Migrate from a struggling hosted server provider to an in-house IT environment without disruption to operations.\",\"Lack of strategic technology roadmap for scalability, growth, and future innovation.\",\"Need for stable, secure, and efficient infrastructure to support mission-critical senior care services.\"],\"services\":[\"Conducted a comprehensive IT and infrastructure assessment to identify gaps and priorities.\",\"Designed and executed a data center and technology conversion with rapid stabilization of systems.\",\"Remediated legacy vendor issues and established a long-term technology roadmap.\",\"Deployed and managed core IT services including collaboration tools, infrastructure, security, and operations support.\",\"Implemented real-time monitoring, automation, and centralized documentation for improved efficiency and visibility.\"],\"outcomes\":[\"Successfully transitioned to a stable, scalable in-house IT infrastructure with minimal disruption.\",\"Improved operational efficiency through streamlined workflows and modern collaboration tools.\",\"Enhanced security, reliability, and system performance across the organization.\",\"Enabled continuous innovation through ongoing strategic IT planning and managed services.\",\"Established a long-term strategic partnership supporting digital transformation and mission delivery.\"],\"narrative\":\"xFact’s healthcare engagement with Ohio Masonic Home demonstrates how strategic infrastructure modernization and managed services can transform IT from a support function into a scalable, mission-critical utility that drives operational excellence and innovation.\"} /-->\n\n<!-- wp:xfact/cta-section {\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'Healthcare', '', 'publish', 'closed', 'closed', '', 'healthcare', '', '', '2026-05-17 03:43:54', '2026-05-17 03:43:54', '', '0', 'https://xfact2stg.wpenginepowered.com/case-studies/healthcare/', '0', 'case_study', '', '0'),
('175', '0', '2026-05-12 14:39:28', '2026-05-12 14:39:28', '<!-- wp:xfact/hero {\"sectionLabel\":\"Case Studies\",\"title\":\"HHS Child Welfare Case Management System Modernization\",\"subtitle\":\"Modernized a legacy child welfare system with a mobile-first, user-centric platform, enhancing accessibility, efficiency, and service delivery for both agency staff and the public.\"} /-->\n\n<!-- wp:xfact/case-study-details {\"summary\":\"Modernization of a state child-welfare case-management platform, replacing siloed legacy tooling with an integrated system.\",\"source\":\"xFact\",\"client\":\"State-wide Agency for Children and Families\",\"challenge\":[\"Modernizing the core technology platform and infrastructure of a critical legacy system to align with the agency\'s strategic goals and operational constraints\",\"Implementing a new, user-driven design to ensure a consistent and effective UI/UX across a diverse user base (including a mobile workforce of over 3,000)\",\"Ensuring secure and efficient mobile access to the agency’s technology platform, tailored to the unique context of each user\'s work environment\"],\"services\":[\"Aligned the modernization effort with the agency’s strategic objectives, internal business processes, and legal/operational constraints, ensuring a holistic approach to modernization\",\"Collaboratively designed and implemented updates to the legacy system’s core technology stack and application architecture to support modernization efforts and long-term sustainability of the solution\",\"Designed and developed a modern, intuitive responsive user interface for desktops, tablets, and mobile devices to facilitate easier access and interaction for all users\",\"Developed a public-facing digital platform that allows the public and mandated reporters to easily report child abuse and neglect through the state\'s portal\"],\"outcomes\":[\"Mitigation of technical debt and increased sustainability and extensibility of the legacy system application architecture\",\"Significant improvements to the end-user experience, leading to increased satisfaction and productivity among the agency’s workforce and mobile user base\",\" By leveraging the agency’s public website as a digital channel, the system extended the reach and impact of HHS services, aligning with the agency’s mission to provide constituent-centric services and offering easier processes for constituents and mandated reporters to report child abuse and neglect, promoting timelier interventions and support.\",\"Real-time access to information via tablets and smartphones, enhancing decision-making capabilities in the field\"],\"narrative\":\"The Enterprise Modernization and Mobility Project exemplifies the xFact team\\u005c\'s commitment to leveraging innovative technology solutions to improve public service delivery. By prioritizing user experience and embracing a mobile-first approach, the project has set a new standard for digital engagement and operational efficiency within the HHS agency, making a tangible difference in the lives of both the agency\'s employees and the populations they serve.\"} /-->\n\n<!-- wp:xfact/cta-section {\"title\":\"Ready to strengthen your systems?\",\"subtitle\":\"Schedule an assessment to understand your current environment and identify a path forward.\",\"buttons\":[{\"label\":\"Contact Us\",\"url\":\"/contact\",\"variant\":\"primary\"}]} /-->', 'HHS Child Welfare Case Management System Modernization', '', 'publish', 'closed', 'closed', '', 'hhs-child-welfare-case-management-system-modernization', '', '', '2026-05-17 03:43:54', '2026-05-17 03:43:54', '', '0', 'https://xfact2stg.wpenginepowered.com/case-studies/hhs-child-welfare-case-management-system-modernization/', '0', 'case_study', '', '0'),
('278', '1', '2026-05-14 18:43:54', '0000-00-00 00:00:00', '<!-- wp:navigation-link {\"label\":\"About\",\"url\":\"/about\",\"className\":\"xfact-desktop-nav__link\"} /-->\n\n<!-- wp:navigation-submenu {\"label\":\"Solutions\",\"url\":\"/solutions\",\"className\":\"xfact-desktop-nav__link\"} -->\n<!-- wp:navigation-link {\"label\":\"Public Safety \\u0026 Justice\",\"url\":\"/solutions/public-safety\"} /-->\n\n<!-- wp:navigation-link {\"label\":\"Municipal, State \\u0026 Local Government\",\"url\":\"/solutions/government\"} /-->\n\n<!-- wp:navigation-link {\"label\":\"Education\",\"url\":\"/solutions/education\"} /-->\n\n<!-- wp:navigation-link {\"label\":\"Health \\u0026 Human Services\",\"url\":\"/solutions/health-and-human-services\"} /-->\n\n<!-- wp:navigation-link {\"label\":\"Infrastructure \\u0026 Managed Services\",\"url\":\"/solutions/infrastructure\"} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Capabilities\",\"url\":\"/capabilities\",\"className\":\"xfact-desktop-nav__link\"} /-->\n\n<!-- wp:navigation-link {\"label\":\"News \\u0026 Insights\",\"url\":\"/news\",\"className\":\"xfact-desktop-nav__link\"} /-->\n\n<!-- wp:navigation-link {\"label\":\"Support\",\"url\":\"/support\",\"className\":\"xfact-desktop-nav__link\"} /-->\n\n<!-- wp:navigation-link {\"label\":\"Careers\",\"url\":\"/careers\",\"className\":\"xfact-desktop-nav__link\"} /-->\n\n<!-- wp:navigation-link {\"label\":\"\",\"url\":\"/leadership\",\"className\":\"xfact-desktop-nav__link\"} /-->', 'Menu', '', 'draft', 'closed', 'closed', '', '', '', '', '2026-05-14 18:43:54', '0000-00-00 00:00:00', '', '0', 'https://xfact2stg.wpenginepowered.com/?p=278', '0', 'wp_navigation', '', '0'),
